   205→        Log.i(TAG, "onScanVolume sInternalScanned = " + sInternalScanned);
   206→        if (!MediaStore.VOLUME_INTERNAL.equals(volumeName) &&
   207→                (reason != REASON_MOUNTED || !sInternalScanned)) {
   208→            // 标记内部存储已扫描，避免重复扫描
   209→            sInternalScanned = true;
   210→            // 递归调用，先扫描内部存储
   211→            onScanVolume(context, MediaVolume.fromInternal(), reason);
