   222→        } else {
   223→            // 内部存储：不需要广播Uri
   224→            broadcastUri = null;
   225→        }
   226→
   227→        // 使用try-with-resources确保ContentProviderClient正确释放
   228→        try (ContentProviderClient cpc = context.getContentResolver()
   229→                .acquireContentProviderClient(MediaStore.AUTHORITY)) {
   230→            // 获取MediaProvider实例
   231→            final MediaProvider provider = ((MediaProvider) cpc.getLocalContentProvider());
   232→            
   233→            // 【重要】附加卷到MediaProvider，并进行验证
   234→            provider.attachVolume(volume, /* validate */ true);
   235→
   236→            // 包装ContentResolver用于数据库操作
   237→            final ContentResolver resolver = ContentResolver.wrap(cpc.getLocalContentProvider());
   238→
