   348→        private void walkFileTree() {
   349→            // 【取消检查】确保扫描任务没有被取消
   350→            mSignal.throwIfCanceled();
   351→            
   352→            // 【目录权限检查】判断目标目录是否可扫描以及是否为隐藏目录
   353→            // 单文件扫描时检查父目录，目录扫描时检查根目录本身
   354→            final Pair<Boolean, Boolean> isDirScannableAndHidden =
   355→                    shouldScanPathAndIsPathHidden(mSingleFile ? mRoot.getParentFile() : mRoot);
   356→            
   357→            if (isDirScannableAndHidden.first) {
   358→                // 该目录可以被扫描，开始执行文件遍历
   359→                Trace.beginSection("walkFileTree");
   360→
   361→                if (isDirScannableAndHidden.second) {
   362→                    // 该目录是隐藏目录，增加隐藏目录计数
   363→                    mHiddenDirCount++;
   364→                }
   365→                
   366→                // 【文件锁处理】单文件扫描时需要获取父目录锁，防止并发访问冲突
   367→                if (mSingleFile) {
   368→                    acquireDirectoryLock(mRoot.getParentFile().toPath());
   369→                }
   370→                
   371→                try {
   372→                    // 【核心文件遍历】根据存储类型采用不同的遍历策略
   373→                    if (mFilesUri.equals(MediaStore.Files.EXTERNAL_CONTENT_URI)) {
