   379→                        Files.walkFileTree(mRoot.toPath(), this);
   380→                    }
   381→                    
   382→                    // 【批量处理】应用所有待处理的数据库操作
   383→                    // 在文件遍历过程中，数据库操作被缓存起来，这里统一执行以提高性能
   384→                    applyPending();
