   386→                } catch (IOException e) {
   387→                    // 【异常处理】文件遍历过程中发生IO异常
   388→                    // 这种情况理论上不应该发生，如果发生说明有严重问题
   389→                    throw new IllegalStateException(e);
   390→                } finally {
   391→                    // 【资源清理】确保在任何情况下都能正确释放资源
   392→                    if (mSingleFile) {
   393→                        // 释放单文件扫描时获取的目录锁
   394→                        releaseDirectoryLock(mRoot.getParentFile().toPath());
   395→                    }
   396→                    // 结束性能跟踪
   397→                    Trace.endSection();
   398→                }
   399→            }
   400→        }
