   492→
   493→                    // 【目录特殊处理】目录不需要内容变化检查，直接跳过
   494→                    if (attrs.isDirectory()) {
   495→                        recordCountByMediaType(mediaType);
   496→                        if (LOGV) {
   497→                          Log.v(TAG, "Skipping unchanged " + file);
   498→                        }
   499→                        return FileVisitResult.CONTINUE;
   500→                    }
   501→
   502→                    // 【变化检测】检查文件元数据和媒体类型是否发生变化
   503→                    final boolean sameMetadata =
   504→                            hasSameMetadata(attrs, realFile, isPendingFromFuse, c);
   505→                    final boolean sameMediaType = actualMediaType == mediaType;
   506→                    
   507→                    // 【性能优化】如果元数据和媒体类型都未变化，跳过处理
   508→                    if (sameMetadata && sameMediaType) {
   509→                        if (LOGV) Log.v(TAG, "Skipping unchanged " + file);
   510→                        return FileVisitResult.CONTINUE;
   511→                    }
   512→
   513→                    // 【MP4特殊情况】处理MP4文件的video/audio类型转换
   514→                    // 由于文件元数据可能导致MIME类型从audio/mp4变为video/mp4，这是安全的
   515→                    // 因为MIME类型只能在扫描过程中改变
   516→                    if (sameMetadata
   517→                            && "video/mp4".equalsIgnoreCase(actualMimeType)
   518→                            && "audio/mp4".equalsIgnoreCase(mimeType)) {
   519→                        if (LOGV) Log.v(TAG, "Skipping unchanged video/audio " + file);
   520→                        return FileVisitResult.CONTINUE;
   521→                    }
   522→                }
   523→
   524→                // 【M4A MIME类型自定义】允许顶层MIME类型自定义，需要早期处理
   525→                // 确保文件以正确的类型进行扫描（否则音频文件可能被当作视频扫描，
   526→                // 导致缺失正确的元数据）
   527→                actualMimeType = updateM4aMimeType(realFile, actualMimeType);
   528→                actualMediaType =
   529→                        mediaTypeFromMimeType(realFile, actualMimeType, actualMediaType);
   530→            } finally {
   531→                Trace.endSection();
   532→            }
   533→
   534→            // 【文件扫描处理】创建数据库操作以插入或更新文件信息
   535→            final ContentProviderOperation.Builder op;
   536→            Trace.beginSection("scanItem");
   537→            try {
   538→                // 执行具体的文件扫描，生成数据库操作
   539→                op = scanItem(existingId, realFile, attrs, actualMimeType, actualMediaType,
   540→                        mVolumeName);
   541→            } finally {
   542→                Trace.endSection();
   543→            }
   544→            
   545→            // 【数据库操作构建】如果扫描成功，构建最终的数据库操作
   546→            if (op != null) {
   547→                // 【修改标记】标记操作来源为媒体扫描
   548→                op.withValue(FileColumns._MODIFIER, FileColumns._MODIFIER_MEDIA_SCAN);
   549→                
   550→                // 【所有者包名】为新插入的文件添加所有者包名（如果提供）
   551→                if (op.build().isInsert() && !attrs.isDirectory() && mOwnerPackage != null) {
   552→                    op.withValue(MediaColumns.OWNER_PACKAGE_NAME, mOwnerPackage);
   553→                }
   554→                
   555→                // 【DRM标记】强制标记DRM文件，因为底层协议栈可能不会正确设置
   556→                if (isDrm) {
   557→                    op.withValue(MediaColumns.IS_DRM, 1);
   558→                }
   559→                
   560→                // 【统计记录】记录按媒体类型分类的文件数量
   561→                recordCountByMediaType(actualMediaType);
   562→                
   563→                // 【批量操作】将操作添加到待处理队列
   564→                addPending(op.build());
   565→                
   566→                // 【性能优化】适时应用待处理的批量操作
   567→                maybeApplyPending();
   568→            }
   569→            
   570→            // 【继续遍历】返回继续访问下一个文件
   571→            return FileVisitResult.CONTINUE;
   572→        }
   573→```
