   575→```java
   576→        private String updateM4aMimeType(File file, String defaultMimeType) {
   577→            if ("video/mp4".equalsIgnoreCase(defaultMimeType)) {
   578→                try (
   579→                    FileInputStream is = new FileInputStream(file);
   580→                    MediaMetadataRetriever mmr = new MediaMetadataRetriever()) {
   581→                    mmr.setDataSource(is.getFD());
   582→                    String refinedMimeType = mmr.extractMetadata(METADATA_KEY_MIMETYPE);
   583→                    if ("audio/mp4".equalsIgnoreCase(refinedMimeType)) {
   584→                        return refinedMimeType;
   585→                    }
   586→                } catch (Exception e) {
   587→                    return defaultMimeType;
   588→                }
   589→            }
   590→            return defaultMimeType;
   591→        }
