    17→            // 异步准备播放器
    18→            mediaPlayer.setOnPreparedListener(mp ->{
    19→                Log.d(TAG, "MediaPlayer准备完成，开始播放")
    20→                mediaPlayer.start();// 开始播放
    21→            });
    22→            mediaPlayer.prepareAsync(); // 异步准备
    23→        } catch (Exception e) {
    24→            Log.e("MediaPlayer", "初始化失败：" + e.getMessage());
    25→        }
    26→        //播放进行中
    27→        mediaPlayer.pause(); // 暂停播放
    28→        mediaPlayer.stop(); // 停止播放
    29→        mediaPlayer.release(); // 停止后需要重新准备播放器
