   260→
   261→    if ((strncmp(url, "http://", 7) == 0) ||
   262→        (strncmp(url, "https://", 8) == 0) ||
   263→        (strncmp(url, "rtsp://", 7) == 0)) {
   264→        if (!checkPermission("android.permission.INTERNET")) {
   265→            return PERMISSION_DENIED;
   266→        }
   267→    }
   268→
   269→//ContentProvider是Android系统中四大组件之一，用于在不同应用之间安全地共享数据
   270→    if (strncmp(url, "content://", 10) == 0) {
   271→        // get a filedescriptor for the content Uri and
   272→        // pass it to the setDataSource(fd) method
   273→
   274→        String16 url16(url);
   275→        int fd = android::openContentProviderFile(url16);
   276→        if (fd < 0)
   277→        {
   278→            ALOGE("Couldn't open fd for %s", url);
   279→            return UNKNOWN_ERROR;
   280→        }
   281→        status_t status = setDataSource(fd, 0, 0x7fffffffffLL); // this sets mStatus
   282→        close(fd);
   283→        return mStatus = status;
   284→    } else {
   285→        //获取player的种类，目前只有nuplayer、testplayer 
   286→        //获取哪种的方法 时使用打分制度来评比的，看哪种player更适合当前的url
   287→        player_type playerType = MediaPlayerFactory::getPlayerType(this, url);
   288→        sp<MediaPlayerBase> p = setDataSource_pre(playerType);
   289→        if (p == NULL) {
   290→            return NO_INIT;
   291→        }
   292→
   293→        return mStatus =
   294→                setDataSource_post(
   295→                p, p->setDataSource(httpService, url, headers));
   296→    }
   297→} 
