   397→status_t NuPlayerDriver::setDataSource(
   398→        const sp<IMediaHTTPService> &httpService,
   399→        const char *url,
   400→        const KeyedVector<String8, String8> *headers) {
   401→    ALOGV("setDataSource(%p) url(%s)", this, uriDebugString(url, false).c_str());
   402→    ATRACE_BEGIN(StringPrintf("setDataSource(%p)", this).c_str());
   403→    Mutex::Autolock autoLock(mLock);
   404→
   405→    if (mState != STATE_IDLE) {
   406→        ATRACE_END();
   407→        return INVALID_OPERATION;
   408→    }
   409→    //设置状态 media中状态很重要
   410→    mState = STATE_SET_DATASOURCE_PENDING;
   411→
   412→    mPlayer->setDataSourceAsync(httpService, url, headers);
   413→    //通过while循环来模拟同步
   414→    while (mState == STATE_SET_DATASOURCE_PENDING) {
   415→        mCondition.wait(mLock);
   416→    }
   417→    ATRACE_END();
   418→
   419→    return mAsyncResult;
   420→}
