   741→void NuPlayer::GenericSource::onPrepareAsync() {
   742→
   743→  // 延迟创建数据源（如果数据源还未创建）使用 网址或者本地路径都是没有创建数据源的
   744→  if (mDataSource == NULL) {
   745→    // 初始设置为非安全，如果提取器返回安全标志，再设为true
   746→    mIsSecure = false;
   747→
   748→    // 从URI创建数据源（通常是HTTP/HTTPS流媒体或本地文件URI）
   749→    if (!mUri.empty()) {
   750→      const char *uri = mUri.c_str();
   751→      String8 contentType;
   752→      // 处理HTTP/HTTPS流媒体
   753→      if (!strncasecmp("http://", uri, 7) || !strncasecmp("https://", uri, 8)) {
   754→        sp<DataSource> httpSource;
   755→        // 创建HTTP数据源
   756→        httpSource =
   757→            PlayerServiceDataSourceFactory::getInstance()->CreateMediaHTTP(
   758→                mHTTPService);
   759→        // 如果在创建过程中没有断开连接，保存HTTP源
   760→        if (!mDisconnected) {
   761→          mHttpSource = httpSource;
   762→        }
   763→      }
   764→      // 从URI创建数据源（可能耗时较长，特别是网络连接不稳定时）
   765→      // 这里的mHttpSource并不是最终用于解码的“数据源”，而是作为底层HTTP连接的实现对象（HTTPBase），
   766→      // 真正的DataSource（如NuCachedSource2）会基于这个HTTPBase对象进行缓存和数据读取等高级操作。
   767→      // 因此，这里需要通过CreateFromURI再创建一层“包装”后的DataSource，供后续Extractor等模块使用。
   768→      sp<DataSource> dataSource =
   769→          PlayerServiceDataSourceFactory::getInstance()->CreateFromURI(
   770→              mHTTPService, uri, &mUriHeaders, &contentType,
   771→              static_cast<HTTPBase *>(mHttpSource.get()));
   772→      if (!mDisconnected) {
   773→        mDataSource = dataSource;  // 设置数据源
   774→      }
   775→    } else {
   776→      // 处理文件描述符（fd）方式的数据源
   777→
   778→      if (property_get_bool("media.stagefright.extractremote", true) &&
   779→          !PlayerServiceFileSource::requiresDrm(mFd.get(), mOffset, mLength,
   780→                                                nullptr /* mime */)) {
   781→        // 尝试获取媒体提取器服务
   782→        sp<IBinder> binder =
   783→            defaultServiceManager()->getService(String16("media.extractor"));
   784→
   785→          ALOGD("FileSource remote");  // 使用远程提取器
   786→          // 获取媒体提取器服务接口
   787→          sp<IMediaExtractorService> mediaExService(
   788→              interface_cast<IMediaExtractorService>(binder));
   789→          sp<IDataSource> source;
   790→          // 通过提取器服务创建IDataSource
   791→          mediaExService->makeIDataSource(base::unique_fd(dup(mFd.get())),
   792→                                          mOffset, mLength, &source);
   793→            mDataSource = CreateDataSourceFromIDataSource(source);
   794→      }
   795→      // 如果远程提取器失败或不可用，创建本地文件源
   796→      if (mDataSource == nullptr) {
   797→        ALOGD("FileSource local");  // 使用本地文件源
   798→        mDataSource =
   799→            new PlayerServiceFileSource(dup(mFd.get()), mOffset, mLength);
   800→      }
   801→    }
   802→
   803→  }
   804→
   805→
   806→  // 从数据源初始化提取器（这里进行实际的媒体解析，包括获取通道信息等元数据）
   807→  status_t err = initFromDataSource();
   808→  // 处理视频轨道信息（如果存在）
   809→  if (mVideoTrack.mSource != NULL) {
   810→    // 获取视频格式元数据
   811→    sp<MetaData> meta = getFormatMeta_l(false /* audio */);
   812→    sp<AMessage> msg = new AMessage;
   813→    // 将元数据转换为消息格式
   814→    err = convertMetaDataToMessage(meta, &msg);
   815→    // 通知视频尺寸变化（向上层报告视频分辨率信息）
   816→    notifyVideoSizeChanged(msg);
   817→  }
   818→
   819→  // 设置播放器能力标志
   820→  uint32_t flags = FLAG_CAN_PAUSE | FLAG_CAN_SEEK_BACKWARD |
   821→                   FLAG_CAN_SEEK_FORWARD | FLAG_CAN_SEEK;
   822→                   
   823→  // 检查是否为VBR（可变比特率）音频，设置动态时长标志
   824→  if (mExtractor != NULL) {
   825→    sp<MetaData> meta = mExtractor->getMetaData();
   826→    if (meta != NULL) {
   827→      int32_t isVBR = 0;
   828→      if (meta->findInt32('iVbr', &isVBR) && isVBR != 0) {
   829→        ALOGV("Is VBR");  // 是可变比特率
   830→        mIsDynamicDuration = true;
   831→        flags |= FLAG_DYNAMIC_DURATION;  // 设置动态时长标志
   832→      }
   833→    }
   834→  }
   835→
   836→  // FLAG_SECURE 和 FLAG_PROTECTED 将在应用调用 prepareDrm 时确定
   837→  
   838→  // 检查提取器是否支持跳转
   839→  if (!(mExtractor->flags() & FLAG_CAN_SEEK)) {
   840→    flags &= ~FLAG_CAN_SEEK;  // 清除跳转标志
   841→  }
   842→  // 通知标志变更 更新NuPlayterDriver的状态
   843→  notifyFlagsChanged(flags);
   844→  // 完成异步准备过程
   845→  finishPrepareAsync();
   846→  ALOGV("onPrepareAsync: Done");  // 异步准备完成
   847→}
