   850→status_t NuPlayer::GenericSource::initFromDataSource() {
   851→    //1.创建extractor  //在MediaExtractorFactory.cpp sniff中判断哪一个so最合适
   852→    extractor = MediaExtractorFactory::Create(dataSource, NULL);
   853→    //2.获取meta数据 用来获取duration
   854→    sp<MetaData> fileMeta = extractor->getMetaData();
   855→
   856→    //3. 获取音视频轨道数量,包括音频轨道(如AAC/MP3)和视频轨道(如H264/HEVC)
   857→    size_t numtracks = extractor->countTracks();
   858→
   859→    mFileMeta = fileMeta;
   860→    if (mFileMeta != NULL) {
   861→        int64_t duration;
   862→        if (mFileMeta->findInt64(kKeyDuration, &duration)) {
   863→            mDurationUs = duration;
   864→        }
   865→    }
   866→
   867→    int32_t totalBitrate = 0;
   868→    //4. 记录AVTrack 的信息到mSource中
   869→    for (size_t i = 0; i < numtracks; ++i) {
   870→        sp<IMediaSource> track = extractor->getTrack(i); // 在extracor中会创建对应的source，比如AACSOURCE 
   871→        sp<MetaData> meta = extractor->getTrackMetaData(i);
   872→// mime保存的数据为 audio/aac   video/mp4  image/jpeg这种
   873→        const char *mime;
   874→        CHECK(meta->findCString(kKeyMIMEType, &mime));
   875→        // 只保存第一个音频轨道和视频轨道的原因:
   876→        // 1. Android MediaPlayer默认只支持同时播放一个音频和一个视频轨道
   877→        // 2. 如果有多个音视频轨道,只选择第一个作为默认播放轨道
   878→        // 3. 后续可以通过selectTrack()接口切换到其他轨道播放
   879→        if (!strncasecmp(mime, "audio/", 6)) {
   880→            // mAudioTrack.mSource为空表示还未设置过音频轨道
   881→            if (mAudioTrack.mSource == NULL) {
   882→                mAudioTrack.mIndex = i;
   883→                mAudioTrack.mSource = track;
   884→                mAudioTrack.mPackets =
   885→                    new AnotherPacketSource(mAudioTrack.mSource->getFormat());
   886→
   887→                // 判断音频编码格式是否为Vorbis格式
   888→                // strcasecmp用于比较两个字符串,忽略大小写
   889→                // MEDIA_MIMETYPE_AUDIO_VORBIS 定义为 "audio/vorbis"
   890→                // Vorbis是一种开源的音频压缩编码格式,常用于OGG容器格式
   891→                if (!strcasecmp(mime, MEDIA_MIMETYPE_AUDIO_VORBIS)) {
   892→                    mAudioIsVorbis = true;
   893→                } else {
   894→                    mAudioIsVorbis = false;
   895→                }
   896→
   897→                mMimes.add(String8(mime));
   898→            }
   899→            // 如果mAudioTrack.mSource不为空,表示已经设置过音频轨道,则忽略后续的音频轨道
   900→        } else if (!strncasecmp(mime, "video/", 6)) {
   901→            // mVideoTrack.mSource为空表示还未设置过视频轨道
   902→            if (mVideoTrack.mSource == NULL) {
   903→                mVideoTrack.mIndex = i;
   904→                mVideoTrack.mSource = track;
   905→                mVideoTrack.mPackets =
   906→                    new AnotherPacketSource(mVideoTrack.mSource->getFormat());
   907→
   908→                // video always at the beginning
   909→                mMimes.insertAt(String8(mime), 0);
   910→            }
   911→            // 如果mVideoTrack.mSource不为空,表示已经设置过视频轨道,则忽略后续的视频轨道
   912→        }
   913→        mSources.push(track);
   914→        int64_t durationUs;
   915→        if (meta->findInt64(kKeyDuration, &durationUs)) {
   916→            if (durationUs > mDurationUs) {
   917→                mDurationUs = durationUs;
   918→            }
   919→        }
   920→        int32_t bitrate;
   921→        if (totalBitrate >= 0 && meta->findInt32(kKeyBitRate, &bitrate)) {
   922→            totalBitrate += bitrate;
   923→        } else {
   924→            totalBitrate = -1;
   925→        }
   926→    }
   927→    mBitrate = totalBitrate;
   928→
   929→    return OK;
   930→}
