   946→```c++
   947→
   948→void NuPlayer::GenericSource::finishPrepareAsync() { 
   949→    // 启动音视频数据源，主要就是向MediaBufferGroup申请buffer
   950→    status_t err = startSources();
   951→
   952→    // 如果是流媒体数据
   953→    if (mIsStreaming) {
   954→        // 恢复缓存源的数据获取
   955→        mCachedSource->resumeFetchingIfNecessary();
   956→        // 设置准备状态标志,表示正在准备中
   957→        mPreparing = true;
   958→        // 调度缓冲区轮询
   959→        // 对于流媒体数据,需要等待缓冲足够的数据才能通知准备完成
   960→        // 在onPollBuffering()中会检查缓冲进度
   961→        // 当缓冲达到要求时会调用notifyPrepared()通知准备完成
   962→        schedulePollBuffering();
   963→    } else {
   964→        // 非流媒体直接通知准备完成,通知app当前是MEDIA_PREPARED状态
   965→        notifyPrepared();
   966→    }
   967→
   968→    // 如果存在音频轨道,发送读取音频数据的消息
   969→    if (mAudioTrack.mSource != NULL) {
   970→        postReadBuffer(MEDIA_TRACK_TYPE_AUDIO);
   971→    }
   972→
   973→    // 如果存在视频轨道,发送读取视频数据的消息 
   974→    if (mVideoTrack.mSource != NULL) {
   975→        postReadBuffer(MEDIA_TRACK_TYPE_VIDEO);
   976→    }
   977→}
