  1697→#### NuPlayer reset 
  1698→```c++
  1699→void NuPlayer::resetAsync() {
  1700→    sp<Source> source;
  1701→    {
  1702→        Mutex::Autolock autoLock(mSourceLock);
  1703→        source = mSource;
  1704→    }
  1705→
  1706→    if (source != NULL) {
  1707→        // 在重置过程中,数据源可能已经无响应,我们需要显式断开连接以便读取操作能够及时退出
  1708→        // 我们不能将断开连接的请求排队到looper中,因为它可能排在一个卡住的读取操作后面而永远无法处理
  1709→        // 在looper外部执行断开连接操作,允许挂起的读取操作退出(成功或出错)
  1710→        source->disconnect();
  1711→    }
  1712→
  1713→    (new AMessage(kWhatReset, this))->post();
  1714→}
  1715→void NuPlayer::onMessageReceived(const sp<AMessage> &msg) {
  1716→    switch (msg->what()) {
  1717→        
  1718→        case kWhatReset:
  1719→        {
  1720→            ALOGV("kWhatReset");
  1721→
  1722→            mResetting = true;
  1723→            // 更新播放计时器,停止计时
  1724→            updatePlaybackTimer(true /* stopping */, "kWhatReset");
  1725→            // 更新缓冲计时器,停止计时并标记退出播放
  1726→            updateRebufferingTimer(true /* stopping */, true /* exiting */);
  1727→
  1728→            mDeferredActions.push_back(
  1729→                    new FlushDecoderAction(
  1730→                        FLUSH_CMD_SHUTDOWN /* audio */,
  1731→                        FLUSH_CMD_SHUTDOWN /* video */));
  1732→
  1733→            mDeferredActions.push_back(
  1734→                    new SimpleAction(&NuPlayer::performReset));
  1735→
  1736→            processDeferredActions();
  1737→            break;
  1738→        }}
  1739→}
  1740→void NuPlayer::processDeferredActions() {
  1741→    while (!mDeferredActions.empty()) {
  1742→        // 在解码器处于中间状态(即一个或多个解码器正在刷新或关闭)时,
  1743→        // 我们不会执行任何延迟的动作
  1744→        // 当音频或视频解码器正在刷新时(mFlushingAudio/mFlushingVideo != NONE),
  1745→        // 需要推迟执行重置操作,直到刷新完成
  1746→        // 这是因为在刷新过程中执行重置可能会导致状态不一致
  1747→        if (mFlushingAudio != NONE || mFlushingVideo != NONE) {
  1748→            // We're currently flushing, postpone the reset until that's
  1749→            // completed.
  1750→
  1751→            ALOGV("postponing action mFlushingAudio=%d, mFlushingVideo=%d",
  1752→                  mFlushingAudio, mFlushingVideo);
  1753→
  1754→            break;
  1755→        }
  1756→
  1757→        sp<Action> action = *mDeferredActions.begin();
  1758→        mDeferredActions.erase(mDeferredActions.begin());
  1759→
  1760→        action->execute(this);
  1761→    }
  1762→}
  1763→
  1764→```
  1765→
  1766→# handleFlushComplete函数的调用流程及在release中的作用
  1767→
  1768→`handleFlushComplete`是NuPlayer中处理解码器或渲染器刷新完成事件的关键函数，它在MediaPlayer的生命周期中多次被调用，包括release流程。下面详细分析其调用流程及在release过程中的作用。
  1769→
  1770→## handleFlushComplete函数的基本作用
  1771→
  1772→`handleFlushComplete`函数负责处理两种组件的刷新完成通知：
  1773→1. 解码器(Decoder)的刷新完成
  1774→2. 渲染器(Renderer)的刷新完成
  1775→
  1776→函数签名：
  1777→```cpp
  1778→void NuPlayer::handleFlushComplete(bool audio, bool isDecoder)
  1779→```
  1780→
  1781→参数含义：
  1782→- `audio`: 是音频(true)还是视频(false)组件
  1783→- `isDecoder`: 是解码器(true)还是渲染器(false)
  1784→
  1785→## 调用流程
  1786→
  1787→`handleFlushComplete`的调用流程如下：
  1788→
  1789→### 1. 解码器刷新完成的路径
  1790→
  1791→```mermaid
  1792→graph TD
  1793→    A[Decoder::onFlushCompleted] --> B[kWhatFlushCompleted消息]
  1794→    B --> C[NuPlayer::onMessageReceived]
  1795→    C --> D[NuPlayer::handleFlushComplete<br>audio, true]
  1796→```
  1797→
  1798→当解码器完成刷新操作后，会发送`kWhatFlushCompleted`消息给NuPlayer，NuPlayer在`onMessageReceived`中处理该消息，并调用`handleFlushComplete(audio, true)`。
  1799→
  1800→### 2. 渲染器刷新完成的路径
  1801→
  1802→```mermaid
  1803→graph TD
  1804→    A[Renderer::onFlushComplete] --> B[kWhatFlushComplete消息]
  1805→    B --> C[NuPlayer::onMessageReceived]
  1806→    C --> D[NuPlayer::handleFlushComplete<br>audio, false]
  1807→```
  1808→
  1809→当渲染器完成刷新操作后，会发送`kWhatFlushComplete`消息给NuPlayer，NuPlayer在`onMessageReceived`中处理该消息，并调用`handleFlushComplete(audio, false)`。
  1810→
  1811→## 在release流程中的调用
  1812→
  1813→在MediaPlayer的release流程中，`handleFlushComplete`确实会被调用，具体流程如下：
  1814→
  1815→```mermaid
  1816→graph TD
  1817→    A[MediaPlayer.release] --> B[MediaPlayer.disconnect]
  1818→    B --> C[MediaPlayerService::Client::disconnect]
  1819→    C --> D[MediaPlayerBase::reset]
  1820→    D --> E[NuPlayerDriver::reset]
  1821→    E --> F[NuPlayer::resetAsync]
  1822→    F --> G[FlushDecoderAction<br>FLUSH_CMD_SHUTDOWN]
  1823→    G --> H[NuPlayer::flushDecoder]
  1824→    H --> I[Decoder::signalFlush]
  1825→    I --> J[Decoder::onFlushCompleted]
  1826→    J --> K[NuPlayer::handleFlushComplete<br>audio, true]
  1827→    
  1828→    F --> L[Renderer::flush]
  1829→    L --> M[Renderer::onFlushComplete]
  1830→    M --> N[NuPlayer::handleFlushComplete<br>audio, false]
  1831→```
  1832→
  1833→在release流程中，`handleFlushComplete`的调用是由以下步骤触发的：
  1834→
  1835→1. `MediaPlayer.release()` 调用 `disconnect()`
  1836→2. `disconnect()` 调用 `reset()`
  1837→3. `reset()` 触发 `NuPlayer::resetAsync()`
  1838→4. `resetAsync()` 添加 `FlushDecoderAction(FLUSH_CMD_SHUTDOWN, FLUSH_CMD_SHUTDOWN)` 到延迟队列
  1839→5. `FlushDecoderAction` 执行时调用 `flushDecoder(audio, true)`
  1840→6. `flushDecoder()` 调用 `decoder->signalFlush()`
  1841→7. 解码器完成刷新后，发送 `kWhatFlushCompleted` 消息
  1842→8. NuPlayer处理消息并调用 `handleFlushComplete(audio, true)`
  1843→9. 同样，渲染器完成刷新后也会触发 `handleFlushComplete(audio, false)`
  1844→
  1845→## handleFlushComplete的具体实现
  1846→
  1847→```cpp
  1848→void NuPlayer::handleFlushComplete(bool audio, bool isDecoder) {
  1849→    // 标记对应组件的刷新已完成
  1850→    mFlushComplete[audio][isDecoder] = true;
  1851→    
  1852→    // 如果另一个组件(解码器或渲染器)还未完成刷新，则等待
  1853→    if (!mFlushComplete[audio][!isDecoder]) {
  1854→        return;
  1855→    }
  1856→
  1857→    FlushStatus *state = audio ? &mFlushingAudio : &mFlushingVideo;
  1858→    switch (*state) {
  1859→        case FLUSHING_DECODER:
  1860→        {
  1861→            *state = FLUSHED;
  1862→            break;
  1863→        }
  1864→
  1865→        case FLUSHING_DECODER_SHUTDOWN:
  1866→        {
  1867→            *state = SHUTTING_DOWN_DECODER;
  1868→            // 启动解码器关闭流程
  1869→            getDecoder(audio)->initiateShutdown();
  1870→            break;
  1871→        }
  1872→
  1873→        default:
  1874→            // 解码器刷新只在刷新状态下完成
  1875→            LOG_ALWAYS_FATAL_IF(isDecoder, "decoder flush in invalid state %d", *state);
  1876→            break;
  1877→    }
  1878→}
  1879→```
  1880→
  1881→## 在release中的关键作用
  1882→
  1883→在release流程中，`handleFlushComplete`的关键作用是：
  1884→
  1885→1. **状态转换**：将刷新状态从`FLUSHING_DECODER_SHUTDOWN`转换为`SHUTTING_DOWN_DECODER`
  1886→2. **启动解码器关闭**：调用`decoder->initiateShutdown()`开始解码器的关闭流程
  1887→3. **协调刷新完成**：通过`finishFlushIfPossible()`函数检查所有刷新是否完成，并执行后续操作
  1888→
  1889→当解码器关闭完成后，会再次触发消息，最终调用`finishFlushIfPossible()`，在这个函数中会清除解码器实例：
  1890→
  1891→```cpp
  1892→void NuPlayer::finishFlushIfPossible() {
  1893→    // ...
  1894→    if (audio) {
  1895→        Mutex::Autolock autoLock(mDecoderLock);
  1896→        mAudioDecoder.clear();  // 清除音频解码器实例
  1897→        ++mAudioDecoderGeneration;
  1898→    } else {
  1899→        Mutex::Autolock autoLock(mDecoderLock);
  1900→        mVideoDecoder.clear();  // 清除视频解码器实例
  1901→        ++mVideoDecoderGeneration;
  1902→    }
  1903→    // ...
  1904→}
  1905→```
  1906→
  1907→## 总结
  1908→
  1909→1. `handleFlushComplete`是处理刷新完成事件的关键函数，负责管理解码器和渲染器的状态转换
  1910→2. 在release流程中，它确实会被调用，用于协调解码器的关闭过程
  1911→3. 它通过状态机确保解码器资源被正确释放，是MediaPlayer资源回收的重要环节
  1912→4. 函数的调用是异步的，由解码器和渲染器完成刷新操作后通过消息机制触发
  1913→
  1914→这种设计确保了即使在复杂的异步环境中，MediaPlayer也能安全、有序地释放所有资源，避免内存泄漏和状态混乱。

